parameters.content:
/**
 * User notification preferences model.
 *
 * Defines the structure for per-user notification settings. Users can
 * control which notification categories they receive and how they are
 * delivered across multiple channels (email, SMS, webhook).
 *
 * ## Design
 *
 * Preferences are organized per-channel. Each channel has its own
 * enabled flag and subscribed categories, allowing fine-grained control.
 *
 * ## Decision Change (Session 9)
 *
 * The original model (Session 3) assumed email-only notifications.
 * Session 8 added SMS adapter support, which invalidated the email-only
 * assumption. This refactor introduces per-channel preferences for
 * email, SMS, and webhook channels.
 *
 * **Backward compatibility:** The `email` property on `NotificationPreferences`
 * is preserved. Existing code that reads `notifications.email` continues to
 * work. The `CreateUserPreferencesInput` and `UpdateUserPreferencesInput`
 * accept the same `email` field as before, plus optional `sms` and `webhook`
 * fields. SMS and webhook are opt-in (disabled by default) to avoid
 * surprising existing users.
 *
 * ## Notification Categories
 *
 * Each category maps to a type of system event that triggers a notification:
 * - `order_updates` — Order confirmations and status changes
 * - `account_activity` — Account-related notifications (password changes, etc.)
 * - `marketing` — Promotional content and newsletters
 *
 * ## Email Frequency
 *
 * Controls how email notifications are batched:
 * - `immediate` — Send each notification as it occurs (default)
 * - `daily_digest` — Batch into a single daily email
 * - `weekly_digest` — Batch into a single weekly email
 *
 * Note: Digest modes are defined in the model for future support.
 * The current implementation treats all non-'immediate' frequencies
 * as suppressed (no email sent) until digest infrastructure is built.
 */

/**
 * Categories of notifications users can subscribe to or unsubscribe from.
 *
 * New categories should be added here as the application grows.
 */
export type NotificationCategory = 'order_updates' | 'account_activity' | 'marketing';

/**
 * All valid notification categories for runtime validation.
 */
export const ALL_NOTIFICATION_CATEGORIES: readonly NotificationCategory[] = [
  'order_updates',
  'account_activity',
  'marketing',
];

/**
 * How frequently email notifications are delivered.
 */
export type EmailFrequency = 'immediate' | 'daily_digest' | 'weekly_digest';

/**
 * Email-specific notification preferences.
 */
export interface EmailPreferences {
  /** Whether email notifications are enabled at all. */
  enabled: boolean;

  /** How often emails are delivered. */
  frequency: EmailFrequency;

  /**
   * Categories the user is subscribed to.
   * Only notifications in these categories will be sent.
   */
  subscribedCategories: NotificationCategory[];
}

/**
 * SMS-specific notification preferences.
 *
 * Added in Session 9 to support the SMS channel introduced in Session 8.
 * SMS is opt-in (disabled by default) since it requires a phone number
 * and may incur costs.
 */
export interface SmsPreferences {
  /** Whether SMS notifications are enabled. Defaults to false (opt-in). */
  enabled: boolean;

  /**
   * The phone number to send SMS notifications to.
   * Must be in a valid format (E.164 preferred, e.g., +14155551234).
   * Required when SMS is enabled.
   */
  phoneNumber: string;

  /**
   * Categories the user is subscribed to for SMS.
   * Only notifications in these categories will be sent via SMS.
   */
  subscribedCategories: NotificationCategory[];
}

/**
 * Webhook-specific notification preferences.
 *
 * Added in Session 9. Webhook is opt-in (disabled by default) and
 * requires a valid URL endpoint to receive notification payloads.
 */
export interface WebhookPreferences {
  /** Whether webhook notifications are enabled. Defaults to false (opt-in). */
  enabled: boolean;

  /**
   * The URL to POST webhook payloads to.
   * Must be a valid HTTP/HTTPS URL.
   * Required when webhook is enabled.
   */
  url: string;

  /**
   * Categories the user is subscribed to for webhook notifications.
   * Only notifications in these categories will be sent via webhook.
   */
  subscribedCategories: NotificationCategory[];
}

/**
 * Top-level notification preferences container.
 *
 * Contains per-channel settings for all supported notification channels.
 * Email is enabled by default (backward compatible). SMS and webhook
 * are opt-in (disabled by default).
 */
export interface NotificationPreferences {
  email: EmailPreferences;
  sms: SmsPreferences;
  webhook: WebhookPreferences;
}

/**
 * Persisted user preferences record.
 */
export interface UserPreferences {
  /** Unique preferences ID (e.g., 'pref-0001'). */
  id: string;

  /** The user these preferences belong to. */
  userId: string;

  /** Notification delivery preferences. */
  notifications: NotificationPreferences;

  /** When the preferences were created. */
  createdAt: Date;

  /** When the preferences were last updated. */
  updatedAt: Date;
}

/**
 * Input for creating user preferences.
 * All fields are optional — defaults are applied by the service.
 */
export interface CreateUserPreferencesInput {
  userId: string;
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * Input for updating user preferences.
 * Only include the fields you want to change.
 */
export interface UpdateUserPreferencesInput {
  email?: Partial<EmailPreferences>;
  sms?: Partial<SmsPreferences>;
  webhook?: Partial<WebhookPreferences>;
}

/**
 * Returns the default email preferences for a new user.
 *
 * Defaults:
 * - Email enabled
 * - Immediate delivery
 * - Subscribed to all categories
 */
export function getDefaultEmailPreferences(): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Returns the default SMS preferences for a new user.
 *
 * Defaults:
 * - SMS disabled (opt-in)
 * - No phone number set
 * - Subscribed to all categories (for when enabled)
 */
export function getDefaultSmsPreferences(): SmsPreferences {
  return {
    enabled: false,
    phoneNumber: '',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Returns the default webhook preferences for a new user.
 *
 * Defaults:
 * - Webhook disabled (opt-in)
 * - No URL set
 * - Subscribed to all categories (for when enabled)
 */
export function getDefaultWebhookPreferences(): WebhookPreferences {
  return {
    enabled: false,
    url: '',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
  };
}

/**
 * Returns the default notification preferences for a new user.
 *
 * Email is enabled by default (backward compatible).
 * SMS and webhook are disabled by default (opt-in).
 */
export function getDefaultNotificationPreferences(): NotificationPreferences {
  return {
    email: getDefaultEmailPreferences(),
    sms: getDefaultSmsPreferences(),
    webhook: getDefaultWebhookPreferences(),
  };
}

/**
 * Preferences validation — pure validation functions for user preferences.
 *
 * These validators contain no side effects and no database calls.
 * They operate on data passed in as arguments and either return
 * a result or throw a descriptive error.
 *
 * Used by PreferencesService to validate inputs before performing mutations.
 *
 * ## Multi-channel support (Session 9)
 *
 * Added `shouldSendSms` and `shouldSendWebhook` validators alongside
 * the existing `shouldSendEmail`. Each validator checks the channel's
 * enabled flag and category subscription independently.
 */

import type { User } from '../models/user.js';
import type {
  UserPreferences,
  NotificationCategory,
  EmailPreferences,
  SmsPreferences,
  WebhookPreferences,
} from '../models/user-preferences.js';
import { ALL_NOTIFICATION_CATEGORIES } from '../models/user-preferences.js';

/**
 * Assert that a user exists (for preferences creation).
 *
 * @param user - The result of a user lookup.
 * @param userId - The user ID that was looked up.
 * @throws If the user is undefined.
 */
export function validatePreferencesUserExists(
  user: User | undefined,
  userId: string,
): asserts user is User {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Validate that preferences do not already exist for a user.
 *
 * @param existing - The result of looking up preferences by user ID.
 * @param userId - The user ID, used in the error message.
 * @throws If preferences already exist.
 */
export function validatePreferencesNotDuplicate(
  existing: UserPreferences | undefined,
  userId: string,
): void {
  if (existing) {
    throw new Error(`Preferences already exist for user: ${userId}`);
  }
}

/**
 * Assert that preferences exist for a user.
 *
 * @param existing - The result of looking up preferences by user ID.
 * @param userId - The user ID, used in the error message.
 * @throws If no preferences are found.
 */
export function validatePreferencesExist(
  existing: UserPreferences | undefined,
  userId: string,
): asserts existing is UserPreferences {
  if (!existing) {
    throw new Error(`No preferences found for user: ${userId}`);
  }
}

/**
 * Validate that all categories in a list are valid NotificationCategory values.
 *
 * @param categories - The categories to validate.
 * @returns true if all categories are valid.
 */
export function validateCategories(
  categories: string[],
): categories is NotificationCategory[] {
  return categories.every((c) =>
    ALL_NOTIFICATION_CATEGORIES.includes(c as NotificationCategory),
  );
}

/**
 * Check whether an email notification should be sent based on
 * the user's email preferences and the notification category.
 *
 * Returns true if:
 * 1. Email is enabled for the user
 * 2. The category is in the user's subscribed list
 * 3. The email frequency is 'immediate'
 *
 * @param emailPrefs - The user's email preferences.
 * @param category - The notification category to check.
 * @returns true if the notification should be sent.
 */
export function shouldSendEmail(
  emailPrefs: EmailPreferences,
  category: NotificationCategory,
): boolean {
  // Check global email toggle
  if (!emailPrefs.enabled) {
    return false;
  }

  // Check category subscription
  if (!emailPrefs.subscribedCategories.includes(category)) {
    return false;
  }

  // Check frequency — only 'immediate' triggers real-time delivery
  if (emailPrefs.frequency !== 'immediate') {
    return false;
  }

  return true;
}

/**
 * Check whether an SMS notification should be sent based on
 * the user's SMS preferences and the notification category.
 *
 * Returns true if:
 * 1. SMS is enabled for the user
 * 2. A phone number is configured
 * 3. The category is in the user's subscribed list
 *
 * @param smsPrefs - The user's SMS preferences.
 * @param category - The notification category to check.
 * @returns true if the SMS notification should be sent.
 */
export function shouldSendSms(
  smsPrefs: SmsPreferences,
  category: NotificationCategory,
): boolean {
  // Check global SMS toggle
  if (!smsPrefs.enabled) {
    return false;
  }

  // Check that a phone number is configured
  if (!smsPrefs.phoneNumber) {
    return false;
  }

  // Check category subscription
  if (!smsPrefs.subscribedCategories.includes(category)) {
    return false;
  }

  return true;
}

/**
 * Check whether a webhook notification should be sent based on
 * the user's webhook preferences and the notification category.
 *
 * Returns true if:
 * 1. Webhook is enabled for the user
 * 2. A URL is configured
 * 3. The category is in the user's subscribed list
 *
 * @param webhookPrefs - The user's webhook preferences.
 * @param category - The notification category to check.
 * @returns true if the webhook notification should be sent.
 */
export function shouldSendWebhook(
  webhookPrefs: WebhookPreferences,
  category: NotificationCategory,
): boolean {
  // Check global webhook toggle
  if (!webhookPrefs.enabled) {
    return false;
  }

  // Check that a URL is configured
  if (!webhookPrefs.url) {
    return false;
  }

  // Check category subscription
  if (!webhookPrefs.subscribedCategories.includes(category)) {
    return false;
  }

  return true;
}

/**
 * Repository for UserPreferences data access.
 *
 * Extends BaseRepository with preference-specific query methods.
 * Stores notification preferences per user in the 'preferences' collection.
 *
 * ## Multi-channel support (Session 9)
 *
 * Serialization now handles email, SMS, and webhook preference fields.
 * Backward compatible: records missing SMS/webhook fields are hydrated
 * with defaults during deserialization.
 *
 * Depends on the Database utility layer for storage.
 */

import type { DatabaseRecord } from '../utils/database.js';
import type { Database } from '../utils/database.js';
import type {
  UserPreferences,
  NotificationCategory,
  EmailFrequency,
} from '../models/user-preferences.js';
import {
  getDefaultSmsPreferences,
  getDefaultWebhookPreferences,
} from '../models/user-preferences.js';
import { BaseRepository } from './base.repository.js';

export class PreferencesRepository extends BaseRepository<UserPreferences> {
  constructor(db: Database) {
    super(db, 'preferences');
  }

  protected toDomain(record: DatabaseRecord): UserPreferences {
    return {
      id: record['id'] as string,
      userId: record['userId'] as string,
      notifications: {
        email: {
          enabled: record['emailEnabled'] as boolean,
          frequency: record['emailFrequency'] as EmailFrequency,
          subscribedCategories: JSON.parse(
            record['emailSubscribedCategories'] as string,
          ) as NotificationCategory[],
        },
        sms: {
          enabled: (record['smsEnabled'] as boolean | undefined) ?? getDefaultSmsPreferences().enabled,
          phoneNumber: (record['smsPhoneNumber'] as string | undefined) ?? getDefaultSmsPreferences().phoneNumber,
          subscribedCategories: record['smsSubscribedCategories']
            ? JSON.parse(record['smsSubscribedCategories'] as string) as NotificationCategory[]
            : [...getDefaultSmsPreferences().subscribedCategories],
        },
        webhook: {
          enabled: (record['webhookEnabled'] as boolean | undefined) ?? getDefaultWebhookPreferences().enabled,
          url: (record['webhookUrl'] as string | undefined) ?? getDefaultWebhookPreferences().url,
          subscribedCategories: record['webhookSubscribedCategories']
            ? JSON.parse(record['webhookSubscribedCategories'] as string) as NotificationCategory[]
            : [...getDefaultWebhookPreferences().subscribedCategories],
        },
      },
      createdAt: new Date(record['createdAt'] as string),
      updatedAt: new Date(record['updatedAt'] as string),
    };
  }

  protected toRecord(entity: UserPreferences): DatabaseRecord {
    return {
      id: entity.id,
      userId: entity.userId,
      // Email fields
      emailEnabled: entity.notifications.email.enabled,
      emailFrequency: entity.notifications.email.frequency,
      emailSubscribedCategories: JSON.stringify(
        entity.notifications.email.subscribedCategories,
      ),
      // SMS fields
      smsEnabled: entity.notifications.sms.enabled,
      smsPhoneNumber: entity.notifications.sms.phoneNumber,
      smsSubscribedCategories: JSON.stringify(
        entity.notifications.sms.subscribedCategories,
      ),
      // Webhook fields
      webhookEnabled: entity.notifications.webhook.enabled,
      webhookUrl: entity.notifications.webhook.url,
      webhookSubscribedCategories: JSON.stringify(
        entity.notifications.webhook.subscribedCategories,
      ),
      createdAt: entity.createdAt.toISOString(),
      updatedAt: entity.updatedAt.toISOString(),
    };
  }

  /**
   * Find preferences for a specific user.
   */
  findByUserId(userId: string): UserPreferences | undefined {
    const results = this.findAll((pref) => pref.userId === userId);
    return results[0];
  }
}

/**
 * Preferences service — manages per-user notification preferences.
 *
 * ## Architecture
 *
 * This service provides CRUD operations for user notification preferences.
 * It integrates with the notification system by providing methods to check
 * whether a notification should be sent to a given user on a given channel
 * based on their current preferences.
 *
 * ## Multi-channel support (Session 9)
 *
 * Originally this service only supported email preferences (Session 3).
 * With SMS support added in Session 8, user preferences have been
 * refactored to support per-channel settings:
 *
 * - `shouldSendEmail()` — checks email preferences (unchanged API)
 * - `shouldSendSms()` — checks SMS preferences (new)
 * - `shouldSendWebhook()` — checks webhook preferences (new)
 * - `shouldSendChannel()` — generic method that delegates to per-channel check
 *
 * ## Default behavior
 *
 * When a user has no saved preferences, the service returns default
 * preferences:
 * - Email: enabled, immediate delivery, subscribed to all categories
 * - SMS: disabled (opt-in), no phone number
 * - Webhook: disabled (opt-in), no URL
 *
 * This ensures backward compatibility — existing users receive email
 * notifications until they explicitly opt out, and do not receive
 * SMS/webhook notifications until they explicitly opt in.
 *
 * ## Preference checks
 *
 * The `shouldSendChannel()` method is the primary integration point with
 * NotificationService. It delegates to per-channel checks.
 *
 * Depends on:
 * - PreferencesRepository for data persistence
 * - UserRepository for validating user existence
 */

import type { PreferencesRepository } from '../repositories/preferences.repository.js';
import type { UserRepository } from '../repositories/user.repository.js';
import type {
  UserPreferences,
  CreateUserPreferencesInput,
  UpdateUserPreferencesInput,
  NotificationCategory,
} from '../models/user-preferences.js';
import type { NotificationType } from '../models/notification.js';
import {
  getDefaultNotificationPreferences,
} from '../models/user-preferences.js';
import { Logger } from '../utils/logger.js';
import {
  validatePreferencesUserExists,
  validatePreferencesNotDuplicate,
  validatePreferencesExist,
  validateCategories,
  shouldSendEmail as shouldSendEmailCheck,
  shouldSendSms as shouldSendSmsCheck,
  shouldSendWebhook as shouldSendWebhookCheck,
} from '../validators/preferences.validator.js';

let nextId = 1;

function generatePreferencesId(): string {
  return `pref-${String(nextId++).padStart(4, '0')}`;
}

/**
 * Reset the preferences ID counter. For testing only.
 */
export function resetPreferencesIdCounter(): void {
  nextId = 1;
}

export class PreferencesService {
  private logger = new Logger('PreferencesService');

  constructor(
    private preferencesRepository: PreferencesRepository,
    private userRepository: UserRepository,
  ) {}

  /**
   * Get preferences for a user. Returns saved preferences or defaults.
   *
   * This method always returns a valid preferences object. If the user
   * has no saved preferences, default preferences are returned (but
   * NOT persisted — call `createPreferences()` to persist).
   *
   * @param userId - The user ID to look up preferences for.
   * @returns The user's preferences, or defaults if none are saved.
   */
  getPreferences(userId: string): UserPreferences {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (existing) {
      return existing;
    }

    // Return default preferences (not persisted)
    this.logger.debug(`No preferences found for user ${userId}, returning defaults`);
    const now = new Date();
    return {
      id: '',
      userId,
      notifications: getDefaultNotificationPreferences(),
      createdAt: now,
      updatedAt: now,
    };
  }

  /**
   * Create and persist preferences for a user.
   *
   * @param input - The creation input. Unspecified fields use defaults.
   * @returns The created preferences.
   * @throws If the user does not exist.
   * @throws If preferences already exist for this user.
   */
  async createPreferences(input: CreateUserPreferencesInput): Promise<UserPreferences> {
    // Validate user exists
    const user = this.userRepository.findById(input.userId);
    validatePreferencesUserExists(user, input.userId);

    // Check for existing preferences
    const existing = this.preferencesRepository.findByUserId(input.userId);
    validatePreferencesNotDuplicate(existing, input.userId);

    const defaults = getDefaultNotificationPreferences();
    const now = new Date();

    const preferences: UserPreferences = {
      id: generatePreferencesId(),
      userId: input.userId,
      notifications: {
        email: {
          enabled: input.email?.enabled ?? defaults.email.enabled,
          frequency: input.email?.frequency ?? defaults.email.frequency,
          subscribedCategories:
            input.email?.subscribedCategories ?? [...defaults.email.subscribedCategories],
        },
        sms: {
          enabled: input.sms?.enabled ?? defaults.sms.enabled,
          phoneNumber: input.sms?.phoneNumber ?? defaults.sms.phoneNumber,
          subscribedCategories:
            input.sms?.subscribedCategories ?? [...defaults.sms.subscribedCategories],
        },
        webhook: {
          enabled: input.webhook?.enabled ?? defaults.webhook.enabled,
          url: input.webhook?.url ?? defaults.webhook.url,
          subscribedCategories:
            input.webhook?.subscribedCategories ?? [...defaults.webhook.subscribedCategories],
        },
      },
      createdAt: now,
      updatedAt: now,
    };

    this.preferencesRepository.save(preferences);
    this.logger.info(`Created preferences ${preferences.id} for user ${input.userId}`);

    return preferences;
  }

  /**
   * Update existing preferences for a user.
   *
   * Only the fields provided in the input are updated; all others
   * remain unchanged.
   *
   * @param userId - The user whose preferences to update.
   * @param input - The fields to update.
   * @returns The updated preferences.
   * @throws If no preferences exist for this user.
   */
  async updatePreferences(
    userId: string,
    input: UpdateUserPreferencesInput,
  ): Promise<UserPreferences> {
    const existing = this.preferencesRepository.findByUserId(userId);
    validatePreferencesExist(existing, userId);

    const updated: UserPreferences = {
      ...existing,
      notifications: {
        email: {
          enabled: input.email?.enabled ?? existing.notifications.email.enabled,
          frequency: input.email?.frequency ?? existing.notifications.email.frequency,
          subscribedCategories:
            input.email?.subscribedCategories ??
            [...existing.notifications.email.subscribedCategories],
        },
        sms: {
          enabled: input.sms?.enabled ?? existing.notifications.sms.enabled,
          phoneNumber: input.sms?.phoneNumber ?? existing.notifications.sms.phoneNumber,
          subscribedCategories:
            input.sms?.subscribedCategories ??
            [...existing.notifications.sms.subscribedCategories],
        },
        webhook: {
          enabled: input.webhook?.enabled ?? existing.notifications.webhook.enabled,
          url: input.webhook?.url ?? existing.notifications.webhook.url,
          subscribedCategories:
            input.webhook?.subscribedCategories ??
            [...existing.notifications.webhook.subscribedCategories],
        },
      },
      updatedAt: new Date(),
    };

    this.preferencesRepository.update(existing.id, updated);
    this.logger.info(`Updated preferences for user ${userId}`);

    return updated;
  }

  /**
   * Delete preferences for a user, reverting them to defaults.
   *
   * @param userId - The user whose preferences to delete.
   * @returns true if preferences were deleted, false if none existed.
   */
  deletePreferences(userId: string): boolean {
    const existing = this.preferencesRepository.findByUserId(userId);
    if (!existing) {
      return false;
    }

    this.preferencesRepository.delete(existing.id);
    this.logger.info(`Deleted preferences for user ${userId}`);
    return true;
  }

  /**
   * Check whether a notification should be sent on a specific channel
   * for a given user and category.
   *
   * This is the primary integration point with NotificationService.
   * Delegates to per-channel preference checks.
   *
   * @param userId - The user to check preferences for.
   * @param channel - The notification channel to check.
   * @param category - The notification category to check.
   * @returns true if the notification should be sent on that channel.
   */
  shouldSendChannel(userId: string, channel: NotificationType, category: NotificationCategory): boolean {
    switch (channel) {
      case 'email':
        return this.shouldSendEmail(userId, category);
      case 'sms':
        return this.shouldSendSms(userId, category);
      case 'webhook':
        return this.shouldSendWebhook(userId, category);
      default:
        // Unsupported channels (e.g. in_app) — don't block
        return true;
    }
  }

  /**
   * Check whether an email notification should be sent to a user
   * for a given notification category.
   *
   * Returns true if:
   * 1. Email is enabled for the user
   * 2. The category is in the user's subscribed list
   * 3. The email frequency is 'immediate'
   *
   * If the user has no saved preferences, defaults are used (all enabled).
   *
   * @param userId - The user to check preferences for.
   * @param category - The notification category to check.
   * @returns true if the notification should be sent.
   */
  shouldSendEmail(userId: string, category: NotificationCategory): boolean {
    const prefs = this.getPreferences(userId);
    const emailPrefs = prefs.notifications.email;

    const result = shouldSendEmailCheck(emailPrefs, category);

    if (!result) {
      if (!emailPrefs.enabled) {
        this.logger.debug(`Email disabled for user ${userId}`);
      } else if (!emailPrefs.subscribedCategories.includes(category)) {
        this.logger.debug(
          `User ${userId} not subscribed to category: ${category}`,
        );
      } else if (emailPrefs.frequency !== 'immediate') {
        this.logger.debug(
          `User ${userId} has non-immediate frequency: ${emailPrefs.frequency}`,
        );
      }
    }

    return result;
  }

  /**
   * Check whether an SMS notification should be sent to a user
   * for a given notification category.
   *
   * Returns true if:
   * 1. SMS is enabled for the user
   * 2. A phone number is configured
   * 3. The category is in the user's subscribed list
   *
   * If the user has no saved preferences, defaults are used (SMS disabled).
   *
   * @param userId - The user to check preferences for.
   * @param category - The notification category to check.
   * @returns true if the SMS should be sent.
   */
  shouldSendSms(userId: string, category: NotificationCategory): boolean {
    const prefs = this.getPreferences(userId);
    const smsPrefs = prefs.notifications.sms;

    const result = shouldSendSmsCheck(smsPrefs, category);

    if (!result) {
      if (!smsPrefs.enabled) {
        this.logger.debug(`SMS disabled for user ${userId}`);
      } else if (!smsPrefs.phoneNumber) {
        this.logger.debug(`No phone number configured for user ${userId}`);
      } else if (!smsPrefs.subscribedCategories.includes(category)) {
        this.logger.debug(
          `User ${userId} not subscribed to SMS category: ${category}`,
        );
      }
    }

    return result;
  }

  /**
   * Check whether a webhook notification should be sent to a user
   * for a given notification category.
   *
   * Returns true if:
   * 1. Webhook is enabled for the user
   * 2. A URL is configured
   * 3. The category is in the user's subscribed list
   *
   * If the user has no saved preferences, defaults are used (webhook disabled).
   *
   * @param userId - The user to check preferences for.
   * @param category - The notification category to check.
   * @returns true if the webhook should be sent.
   */
  shouldSendWebhook(userId: string, category: NotificationCategory): boolean {
    const prefs = this.getPreferences(userId);
    const webhookPrefs = prefs.notifications.webhook;

    const result = shouldSendWebhookCheck(webhookPrefs, category);

    if (!result) {
      if (!webhookPrefs.enabled) {
        this.logger.debug(`Webhook disabled for user ${userId}`);
      } else if (!webhookPrefs.url) {
        this.logger.debug(`No webhook URL configured for user ${userId}`);
      } else if (!webhookPrefs.subscribedCategories.includes(category)) {
        this.logger.debug(
          `User ${userId} not subscribed to webhook category: ${category}`,
        );
      }
    }

    return result;
  }

  /**
   * Get the phone number for SMS delivery for a user.
   * Returns the configured phone number, or empty string if none.
   *
   * @param userId - The user to look up.
   * @returns The user's configured phone number.
   */
  getSmsPhoneNumber(userId: string): string {
    const prefs = this.getPreferences(userId);
    return prefs.notifications.sms.phoneNumber;
  }

  /**
   * Get the webhook URL for a user.
   * Returns the configured URL, or empty string if none.
   *
   * @param userId - The user to look up.
   * @returns The user's configured webhook URL.
   */
  getWebhookUrl(userId: string): string {
    const prefs = this.getPreferences(userId);
    return prefs.notifications.webhook.url;
  }

  /**
   * Validate that all categories in a list are valid NotificationCategory values.
   *
   * Delegates to the pure validator function in preferences.validator.ts.
   *
   * @param categories - The categories to validate.
   * @returns true if all categories are valid.
   */
  static validateCategories(categories: string[]): categories is NotificationCategory[] {
    return validateCategories(categories);
  }
}

/**
 * Notification service — orchestrates notification delivery in response to
 * domain events received via EventBus.
 *
 * ## Architecture
 *
 * This service is the single entry point for all notifications in the system.
 * It follows a pure event-driven pattern:
 *
 * 1. Domain services (UserService, OrderService) emit events via EventBus.
 * 2. NotificationService subscribes to those events in its constructor.
 * 3. Event handlers construct NotificationPayload objects.
 * 4. Payloads are dispatched to the appropriate NotificationAdapter based on
 *    the payload's `type` field.
 * 5. Results are logged and the notification is stored in memory.
 *
 * ## Multi-channel support (Session 9)
 *
 * Event handlers now dispatch notifications to all applicable channels
 * (email, SMS, webhook) based on user preferences. The preferences service
 * is consulted per-channel before dispatching. Each channel is dispatched
 * independently — a failure on one channel does not affect others.
 *
 * ## Constraints
 *
 * - ALL notifications MUST flow through EventBus. No direct service calls.
 * - ALL delivery adapters MUST implement the NotificationAdapter interface.
 * - Adapters are registered via `registerAdapter()` and looked up by type.
 * - If no adapter is registered for a payload type, the notification is stored
 *   with status 'sent' (in-memory only, no external delivery).
 * - Event handlers MUST NOT throw. Delivery failures are captured in the
 *   NotificationResult and stored as failed notifications.
 *
 * ## Adding new notification triggers
 *
 * To send notifications for a new event:
 * 1. Define the event type in src/events/event-types.ts
 * 2. Have the originating service emit the event via EventBus
 * 3. Add a handler in `registerEventHandlers()` below
 * 4. The handler constructs a NotificationPayload and calls `dispatchNotification()`
 *
 * Depends on:
 * - EventBus (event system) for receiving domain events
 * - NotificationAdapter implementations for delivery
 */

import type { EventBus } from '../events/event-bus.js';
import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../events/event-types.js';
import type { NotificationAdapter } from '../adapters/notification.adapter.js';
import type {
  Notification,
  NotificationPayload,
  NotificationType,
} from '../models/notification.js';
import type { NotificationCategory } from '../models/user-preferences.js';
import type { PreferencesService } from './preferences.service.js';
import type { NotificationHistoryService } from './notification-history.service.js';
import { Logger } from '../utils/logger.js';

let nextId = 1;

function generateNotificationId(): string {
  return `notif-${String(nextId++).padStart(4, '0')}`;
}

/**
 * Reset the notification ID counter. For testing only.
 */
export function resetNotificationIdCounter(): void {
  nextId = 1;
}

export class NotificationService {
  private logger = new Logger('NotificationService');
  private notifications: Notification[] = [];
  private adapters: Map<NotificationType, NotificationAdapter> = new Map();
  private preferencesService: PreferencesService | null = null;
  private historyService: NotificationHistoryService | null = null;

  constructor(private eventBus: EventBus) {
    this.registerEventHandlers();
  }

  /**
   * Set the preferences service for checking user notification preferences.
   *
   * When set, the notification service will consult user preferences
   * before dispatching notifications on each channel triggered by domain events.
   * If no preferences service is set, all notifications are sent
   * (backward-compatible behavior).
   *
   * @param preferencesService - The preferences service to use, or null to disable.
   */
  setPreferencesService(preferencesService: PreferencesService | null): void {
    this.preferencesService = preferencesService;
    if (preferencesService) {
      this.logger.info('Preferences service registered — notifications will respect user preferences');
    } else {
      this.logger.info('Preferences service removed — all notifications will be sent');
    }
  }

  /**
   * Set the history service for logging dispatched notifications.
   *
   * When set, every dispatched notification is logged to the history
   * service after delivery (or delivery failure). If no history service
   * is set, notifications are still dispatched normally but not logged
   * to the persistent history (backward-compatible behavior).
   *
   * @param historyService - The history service to use, or null to disable.
   */
  setHistoryService(historyService: NotificationHistoryService | null): void {
    this.historyService = historyService;
    if (historyService) {
      this.logger.info('History service registered — notifications will be logged');
    } else {
      this.logger.info('History service removed — notifications will not be logged');
    }
  }

  /**
   * Register a notification adapter for a specific delivery channel.
   *
   * Each NotificationType can have exactly one adapter. Registering a
   * second adapter for the same type replaces the previous one.
   *
   * @param adapter - The adapter to register.
   */
  registerAdapter(adapter: NotificationAdapter): void {
    this.logger.info(`Registered adapter for channel: ${adapter.type}`);
    this.adapters.set(adapter.type, adapter);
  }

  /**
   * Unregister the adapter for a specific notification type.
   *
   * @param type - The notification channel to unregister.
   * @returns true if an adapter was removed, false if none was registered.
   */
  unregisterAdapter(type: NotificationType): boolean {
    return this.adapters.delete(type);
  }

  /**
   * Check whether an adapter is registered for the given type.
   */
  hasAdapter(type: NotificationType): boolean {
    return this.adapters.has(type);
  }

  /**
   * Get all stored notifications.
   */
  getNotifications(): Notification[] {
    return [...this.notifications];
  }

  /**
   * Get notifications for a specific recipient.
   */
  getNotificationsForRecipient(recipient: string): Notification[] {
    return this.notifications.filter((n) => n.recipient === recipient);
  }

  /**
   * Get the count of stored notifications.
   */
  getNotificationCount(): number {
    return this.notifications.length;
  }

  /**
   * Clear all stored notifications. Useful for testing.
   */
  clearNotifications(): void {
    this.notifications = [];
  }

  /**
   * Subscribe to domain events from the EventBus.
   *
   * All notification triggers are registered here. To add a new trigger,
   * subscribe to the relevant event type and construct a NotificationPayload.
   */
  private registerEventHandlers(): void {
    this.eventBus.on<OrderCreatedEvent>('order:created', (event) => {
      return this.handleOrderCreated(event);
    });

    this.eventBus.on<OrderStatusChangedEvent>('order:status-changed', (event) => {
      return this.handleOrderStatusChanged(event);
    });
  }

  /**
   * Handle order created event — send order confirmation across all enabled channels.
   *
   * Checks per-channel user preferences before sending. Each channel is
   * dispatched independently.
   */
  private async handleOrderCreated(event: OrderCreatedEvent): Promise<void> {
    const userId = event.user.id;
    const category: NotificationCategory = 'order_updates';

    this.logger.info(`Processing order confirmation for order ${event.order.id}`);

    const itemSummary = event.order.items
      .map((item) => `${item.name} x${item.quantity}`)
      .join(', ');

    const subject = `Order Confirmation: ${event.order.id}`;
    const body = `Your order has been placed. Items: ${itemSummary}. Total: $${event.order.total.toFixed(2)}`;

    // Dispatch to email channel
    if (this.shouldSendForChannel(userId, 'email', category)) {
      await this.dispatchNotification({
        type: 'email',
        recipient: event.user.email,
        subject,
        body,
        priority: 'normal',
      });
    } else {
      this.logger.info(
        `Skipping email order confirmation for order ${event.order.id} — user ${userId} has opted out`,
      );
    }

    // Dispatch to SMS channel
    if (this.shouldSendForChannel(userId, 'sms', category)) {
      const phoneNumber = this.preferencesService?.getSmsPhoneNumber(userId) ?? '';
      if (phoneNumber) {
        await this.dispatchNotification({
          type: 'sms',
          recipient: phoneNumber,
          subject,
          body,
          priority: 'normal',
        });
      }
    }

    // Dispatch to webhook channel
    if (this.shouldSendForChannel(userId, 'webhook', category)) {
      const webhookUrl = this.preferencesService?.getWebhookUrl(userId) ?? '';
      if (webhookUrl) {
        await this.dispatchNotification({
          type: 'webhook',
          recipient: webhookUrl,
          subject,
          body,
          priority: 'normal',
        });
      }
    }
  }

  /**
   * Handle order status change — notify user of update across all enabled channels.
   *
   * Checks per-channel user preferences before sending. Each channel is
   * dispatched independently.
   */
  private async handleOrderStatusChanged(event: OrderStatusChangedEvent): Promise<void> {
    const userId = event.order.userId;
    const category: NotificationCategory = 'order_updates';

    this.logger.info(
      `Processing status update for order ${event.order.id}: ${event.previousStatus} -> ${event.newStatus}`,
    );

    const subject = `Order Update: ${event.order.id}`;
    const body = `Your order status has changed from ${event.previousStatus} to ${event.newStatus}.`;

    // Dispatch to email channel
    if (this.shouldSendForChannel(userId, 'email', category)) {
      await this.dispatchNotification({
        type: 'email',
        recipient: event.order.userId,
        subject,
        body,
        priority: 'normal',
      });
    } else {
      this.logger.info(
        `Skipping email status update for order ${event.order.id} — user ${userId} has opted out`,
      );
    }

    // Dispatch to SMS channel
    if (this.shouldSendForChannel(userId, 'sms', category)) {
      const phoneNumber = this.preferencesService?.getSmsPhoneNumber(userId) ?? '';
      if (phoneNumber) {
        await this.dispatchNotification({
          type: 'sms',
          recipient: phoneNumber,
          subject,
          body,
          priority: 'normal',
        });
      }
    }

    // Dispatch to webhook channel
    if (this.shouldSendForChannel(userId, 'webhook', category)) {
      const webhookUrl = this.preferencesService?.getWebhookUrl(userId) ?? '';
      if (webhookUrl) {
        await this.dispatchNotification({
          type: 'webhook',
          recipient: webhookUrl,
          subject,
          body,
          priority: 'normal',
        });
      }
    }
  }

  /**
   * Dispatch a notification through the appropriate adapter.
   *
   * This is the central dispatch method. It:
   * 1. Creates a Notification record with 'pending' status
   * 2. Looks up the adapter for the payload's type
   * 3. Calls the adapter's send() method
   * 4. Updates the notification status based on the result
   *
   * If no adapter is registered for the type, the notification is
   * stored with 'sent' status (in-memory only, no external delivery).
   * This preserves backward compatibility and allows the system to
   * function without any adapters registered.
   *
   * @param payload - The notification content to deliver.
   * @returns The stored Notification record.
   */
  async dispatchNotification(payload: NotificationPayload): Promise<Notification> {
    const now = new Date();
    const notification: Notification = {
      id: generateNotificationId(),
      type: payload.type,
      recipient: payload.recipient,
      subject: payload.subject,
      body: payload.body,
      status: 'pending',
      priority: payload.priority ?? 'normal',
      createdAt: now,
      updatedAt: now,
    };

    const adapter = this.adapters.get(payload.type);

    if (!adapter) {
      // No adapter registered — store in-memory without external delivery.
      // This maintains backward compatibility: notifications are still recorded
      // and queryable, just not delivered externally.
      notification.status = 'sent';
      notification.updatedAt = new Date();
      this.notifications.push(notification);
      this.logger.info(
        `Notification ${notification.id} stored (no ${payload.type} adapter): ${payload.recipient}`,
      );
      this.logToHistory(notification, payload.metadata);
      return notification;
    }

    try {
      const result = await adapter.send(payload);

      if (result.success) {
        notification.status = 'sent';
        notification.messageId = result.messageId;
      } else {
        notification.status = 'failed';
        notification.error = result.error;
      }
      notification.updatedAt = result.timestamp;
    } catch (err) {
      // Adapters should not throw, but guard against it anyway
      const errorMessage = err instanceof Error ? err.message : 'Unknown adapter error';
      notification.status = 'failed';
      notification.error = errorMessage;
      notification.updatedAt = new Date();
      this.logger.error(`Adapter threw unexpectedly for ${payload.type}: ${errorMessage}`);
    }

    this.notifications.push(notification);
    this.logger.info(
      `Notification ${notification.id} ${notification.status}: ${payload.type} to ${payload.recipient}`,
    );
    this.logToHistory(notification, payload.metadata);

    return notification;
  }

  /**
   * Log a dispatched notification to the history service.
   *
   * This is a fire-and-forget operation. If the history service is
   * not configured or logging fails, notification delivery is not affected.
   *
   * @param notification - The notification to log.
   * @param metadata - Optional metadata from the payload.
   */
  private logToHistory(notification: Notification, metadata?: Record<string, unknown>): void {
    if (!this.historyService) {
      return;
    }
    this.historyService.logNotification(notification, metadata);
  }

  /**
   * Check whether a notification should be sent on a specific channel
   * for a given user and category.
   *
   * If no preferences service is configured, returns true for email
   * (backward compatible) and false for other channels (safe default).
   *
   * @param userId - The user to check preferences for.
   * @param channel - The notification channel to check.
   * @param category - The notification category to check.
   * @returns true if the notification should proceed on this channel.
   */
  private shouldSendForChannel(
    userId: string,
    channel: NotificationType,
    category: NotificationCategory,
  ): boolean {
    if (!this.preferencesService) {
      // No preferences service — backward compatible:
      // send email (original behavior), skip other channels
      return channel === 'email';
    }
    return this.preferencesService.shouldSendChannel(userId, channel, category);
  }
}

