        createdAt: new Date(),
        updatedAt: new Date(),
      },
      previousStatus: 'pending',
      newStatus: 'confirmed',
      timestamp: new Date(),
    };

    await eventBus.emit(event);

    expect(notifService.getNotificationCount()).toBe(0);
