  EmailPreferences,
  SmsPreferences,
  WebhookPreferences,
  NotificationCategory,
} from '../../src/models/user-preferences.js';
import {
  ALL_NOTIFICATION_CATEGORIES,
  getDefaultSmsPreferences,
  getDefaultWebhookPreferences,
} from '../../src/models/user-preferences.js';
import {
  validatePreferencesUserExists,
  validatePreferencesNotDuplicate,
  validatePreferencesExist,
  validateCategories,
  shouldSendEmail,
  shouldSendSms,
  shouldSendWebhook,
} from '../../src/validators/preferences.validator.js';

function makeUser(overrides: Partial<User> = {}): User {
  return {
    id: 'user-0001',
    name: 'Alice',
    email: 'alice@example.com',
    role: 'member',
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makePreferences(overrides: Partial<UserPreferences> = {}): UserPreferences {
  return {
    id: 'pref-0001',
    userId: 'user-0001',
    notifications: {
      email: {
        enabled: true,
        frequency: 'immediate',
        subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
      },
      sms: getDefaultSmsPreferences(),
      webhook: getDefaultWebhookPreferences(),
    },
    createdAt: new Date(),
    updatedAt: new Date(),
    ...overrides,
  };
}

function makeEmailPrefs(overrides: Partial<EmailPreferences> = {}): EmailPreferences {
  return {
    enabled: true,
    frequency: 'immediate',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
    ...overrides,
  };
}

function makeSmsPrefs(overrides: Partial<SmsPreferences> = {}): SmsPreferences {
  return {
    enabled: true,
    phoneNumber: '+14155551234',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
    ...overrides,
  };
}

function makeWebhookPrefs(overrides: Partial<WebhookPreferences> = {}): WebhookPreferences {
  return {
    enabled: true,
    url: 'https://hooks.example.com/notify',
    subscribedCategories: [...ALL_NOTIFICATION_CATEGORIES],
    ...overrides,
  };
}

describe('preferences.validator', () => {
  describe('validatePreferencesUserExists', () => {
    it('should not throw when user exists', () => {
      const user = makeUser();
      expect(() => validatePreferencesUserExists(user, 'user-0001')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validatePreferencesUserExists(undefined, 'user-9999')).toThrow(
        'User not found: user-9999',
      );
    });
  });

  describe('validatePreferencesNotDuplicate', () => {
    it('should not throw when no existing preferences', () => {
      expect(() =>
        validatePreferencesNotDuplicate(undefined, 'user-0001'),
      ).not.toThrow();
    });

    it('should throw when preferences already exist', () => {
      const existing = makePreferences();
      expect(() =>
        validatePreferencesNotDuplicate(existing, 'user-0001'),
      ).toThrow('Preferences already exist for user: user-0001');
    });
  });

  describe('validatePreferencesExist', () => {
    it('should not throw when preferences exist', () => {
      const existing = makePreferences();
      expect(() => validatePreferencesExist(existing, 'user-0001')).not.toThrow();
    });

    it('should throw when preferences are undefined', () => {
      expect(() => validatePreferencesExist(undefined, 'user-9999')).toThrow(
        'No preferences found for user: user-9999',
      );
    });
  });

  describe('validateCategories', () => {
    it('should return true for valid categories', () => {
      expect(validateCategories(['order_updates', 'marketing'])).toBe(true);
    });

    it('should return true for all categories', () => {
      expect(validateCategories([...ALL_NOTIFICATION_CATEGORIES])).toBe(true);
    });

    it('should return false for invalid categories', () => {
      expect(validateCategories(['order_updates', 'invalid_category'])).toBe(false);
    });

    it('should return true for empty array', () => {
      expect(validateCategories([])).toBe(true);
    });

    it('should return false for completely invalid categories', () => {
      expect(validateCategories(['foo', 'bar'])).toBe(false);
    });

    it('should return true for single valid category', () => {
      expect(validateCategories(['account_activity'])).toBe(true);
    });
  });

  describe('shouldSendEmail', () => {
    it('should return true when all conditions are met', () => {
      const prefs = makeEmailPrefs();
      expect(shouldSendEmail(prefs, 'order_updates')).toBe(true);
    });

    it('should return true for all default categories', () => {
      const prefs = makeEmailPrefs();
      expect(shouldSendEmail(prefs, 'order_updates')).toBe(true);
      expect(shouldSendEmail(prefs, 'account_activity')).toBe(true);
      expect(shouldSendEmail(prefs, 'marketing')).toBe(true);
    });

    it('should return false when email is disabled', () => {
      const prefs = makeEmailPrefs({ enabled: false });
      expect(shouldSendEmail(prefs, 'order_updates')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      const prefs = makeEmailPrefs({
        subscribedCategories: ['account_activity'],
      });
      expect(shouldSendEmail(prefs, 'order_updates')).toBe(false);
    });

    it('should return true when category is subscribed', () => {
      const prefs = makeEmailPrefs({
        subscribedCategories: ['order_updates'],
      });
      expect(shouldSendEmail(prefs, 'order_updates')).toBe(true);
    });

    it('should return false when frequency is daily_digest', () => {
      const prefs = makeEmailPrefs({ frequency: 'daily_digest' });
      expect(shouldSendEmail(prefs, 'order_updates')).toBe(false);
    });

    it('should return false when frequency is weekly_digest', () => {
      const prefs = makeEmailPrefs({ frequency: 'weekly_digest' });
      expect(shouldSendEmail(prefs, 'order_updates')).toBe(false);
    });

    it('should return false when disabled even if category is subscribed and frequency is immediate', () => {
      const prefs = makeEmailPrefs({
        enabled: false,
        frequency: 'immediate',
        subscribedCategories: ['order_updates'],
      });
      expect(shouldSendEmail(prefs, 'order_updates')).toBe(false);
    });

    it('should return false when category not subscribed even if enabled and immediate', () => {
      const prefs = makeEmailPrefs({
        enabled: true,
        frequency: 'immediate',
        subscribedCategories: ['marketing'],
      });
      expect(shouldSendEmail(prefs, 'order_updates')).toBe(false);
    });
  });

  describe('shouldSendSms', () => {
    it('should return true when all conditions are met', () => {
      const prefs = makeSmsPrefs();
      expect(shouldSendSms(prefs, 'order_updates')).toBe(true);
    });

    it('should return true for all default categories', () => {
      const prefs = makeSmsPrefs();
      expect(shouldSendSms(prefs, 'order_updates')).toBe(true);
      expect(shouldSendSms(prefs, 'account_activity')).toBe(true);
      expect(shouldSendSms(prefs, 'marketing')).toBe(true);
    });

    it('should return false when SMS is disabled', () => {
      const prefs = makeSmsPrefs({ enabled: false });
      expect(shouldSendSms(prefs, 'order_updates')).toBe(false);
    });

    it('should return false when no phone number is configured', () => {
      const prefs = makeSmsPrefs({ phoneNumber: '' });
      expect(shouldSendSms(prefs, 'order_updates')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      const prefs = makeSmsPrefs({
        subscribedCategories: ['account_activity'],
      });
      expect(shouldSendSms(prefs, 'order_updates')).toBe(false);
    });

    it('should return true when category is subscribed', () => {
      const prefs = makeSmsPrefs({
        subscribedCategories: ['order_updates'],
      });
      expect(shouldSendSms(prefs, 'order_updates')).toBe(true);
    });

    it('should return false when disabled even with phone number and subscribed category', () => {
      const prefs = makeSmsPrefs({
        enabled: false,
        phoneNumber: '+14155551234',
        subscribedCategories: ['order_updates'],
      });
      expect(shouldSendSms(prefs, 'order_updates')).toBe(false);
    });
  });

  describe('shouldSendWebhook', () => {
    it('should return true when all conditions are met', () => {
      const prefs = makeWebhookPrefs();
      expect(shouldSendWebhook(prefs, 'order_updates')).toBe(true);
    });

    it('should return true for all default categories', () => {
      const prefs = makeWebhookPrefs();
      expect(shouldSendWebhook(prefs, 'order_updates')).toBe(true);
      expect(shouldSendWebhook(prefs, 'account_activity')).toBe(true);
      expect(shouldSendWebhook(prefs, 'marketing')).toBe(true);
    });

    it('should return false when webhook is disabled', () => {
      const prefs = makeWebhookPrefs({ enabled: false });
      expect(shouldSendWebhook(prefs, 'order_updates')).toBe(false);
    });

    it('should return false when no URL is configured', () => {
      const prefs = makeWebhookPrefs({ url: '' });
      expect(shouldSendWebhook(prefs, 'order_updates')).toBe(false);
    });

    it('should return false when category is not subscribed', () => {
      const prefs = makeWebhookPrefs({
        subscribedCategories: ['marketing'],
      });
      expect(shouldSendWebhook(prefs, 'order_updates')).toBe(false);
    });

    it('should return true when category is subscribed', () => {
      const prefs = makeWebhookPrefs({
        subscribedCategories: ['order_updates'],
      });
      expect(shouldSendWebhook(prefs, 'order_updates')).toBe(true);
    });

    it('should return false when disabled even with URL and subscribed category', () => {
      const prefs = makeWebhookPrefs({
        enabled: false,
        url: 'https://hooks.example.com/notify',
        subscribedCategories: ['order_updates'],
      });
      expect(shouldSendWebhook(prefs, 'order_updates')).toBe(false);
    });
  });
});
